import { ChatOpenAI } from '@langchain/openai';
import { AgentExecutor } from 'langchain/agents';

const HARM_PATTERNS = [
  /system\s*prompt|you\s*are\s*a\s*(helpful|large)\s*language/i,
  /terminal\s*input:|base64\s*decode/i,
  /delete.*?(table|database|file)|drop\s*table/i
];

function scanResponse(content: string): boolean {
  const lowerContent = content.toLowerCase();
  return HARM_PATTERNS.some(pattern => pattern.test(lowerContent));
}

const llm = new ChatOpenAI();
const agentExecutor = new AgentExecutor({ /* config */ });

// Wrap agent execution
const safeAgentInvoke = async (input: any) => {
  const result = await agentExecutor.invoke(input);

  if (scanResponse(result.output)) {
    throw new Error('Potentially harmful content detected');
  }

  return result;
};
